from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

# Define metrics
REQUEST_COUNT = Counter('flask_requests_total', 'Total requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_duration_seconds', 'Request latency in seconds', ['method', 'endpoint'])
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')

@app.before_request
def start_timer():
    request.start_time = time.time()
    ACTIVE_REQUESTS.inc()

@app.after_request
def record_metrics(response):
    ACTIVE_REQUESTS.dec()
    duration = time.time() - request.start_time
    REQUEST_LATENCY.labels(method=request.method, endpoint=request.endpoint or 'unknown').observe(duration)
    REQUEST_COUNT.labels(method=request.method, endpoint=request.endpoint or 'unknown', status=response.status_code).inc()
    return response

@app.route('/')
def home():
    return jsonify({"message": "Hello World"})

@app.route('/health')
def health():
    return jsonify({"status": "healthy"})

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)